import{_ as a,o as t,c as b,j as r,a as n,a1 as p}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"吸血转换装置","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/吸血转换装置.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/吸血转换装置.md"}'),s={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/吸血转换装置.md"};function o(d,e,_,l,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"吸血转换装置",tabindex:"-1"},[n("吸血转换装置 "),r("a",{class:"header-anchor",href:"#吸血转换装置","aria-label":'Permalink to "吸血转换装置"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风029特别节愚人版")])])],-1),p('<h1 id="吸血转换装置-1" tabindex="-1">吸血转换装置 <a class="header-anchor" href="#吸血转换装置-1" aria-label="Permalink to &quot;吸血转换装置&quot;">​</a></h1><p>吸血转换装置<br> D+500<br> 奇物—饰品</p><p>[语言记录A—12]<br> “现在，请重复一遍你是怎么在与叛乱机械的战斗中活下来的”<br> “额啊……好吧好吧，这都要归功于我手中的吸血长剑——”<br> “这就是问题所在，你踏马是怎么从一堆浑身上下凑不出来半点碳的机器人身上抽出血的！”<br> “我踏马怎么知道！”</p><p>[研究记录]<br> 实验编号：03<br> 实验目标：实验体A—03<br> 实验内容：令其持具有吸血能力的匕首刺击金属盒子。<br> 实验结果：无事发生，看样子需要满足吸血能力的前提。</p><p>实验编号：05<br> 实验目标：实验体A—03<br> 实验内容：令其持具有吸血能力的匕首刺击携带有枪械且正在对其发动攻击的机器人。<br> 实验结果：其从机器人身上吸出了疑似血液的液体，对这些液体进行检测结果为，其在含有大量水分以外，还有无机盐、纤维蛋白原、白蛋白、球蛋白、酶、激素、各种营养物质、代谢产物等，并且血型与实验体适配。</p><p>实验编号：34<br> 实验目标：实验体B—03<br> 实验内容：■■■■■■■■■■■■■■■■■■<br> 实验结果：成功。</p><p>[描述]<br> 这是一个冰冷坚硬的吊坠，其上装饰有吸血鬼的齿型图案，<br> 顺带而来的还有一份记录：“在经过众多实验体的【无私】牺牲之后，我们终于明白了他们会和能从明显不具备血液，甚至明显不具备能量的机械身上吸血的原因，其本质上是一种对于物质的转换，<br> 他们在无意间将物质拆解成了能量，然后将能量转化为了血液，之后吸血，对其的模仿使我们学会了更多的能量转换途径，今后的能源将牢牢掌握在我们手中。”</p><p>[效果]<br> 现在你可以将接触到的物质拆分，转化为你能使用的能量，从泥土到空气中的元素再到暗物质，<br> 这些都在这个仪器的使用范围内，获得时绑定一个能量池，每小时一次，进行一次能量池关键属性检定，恢复成功数点能量，这会计入每日的恢复上限。<br> 在战斗开始时，你可以以一个迅捷动作向仪器内注入1点意志力来启动仪器，这会使你该场景内，每轮在计算对方防御步骤后造成至少3点实际伤害后，每具有1点吸血就在回合结束时回复1点完好，表现上是你从构造体身上吸出了血，<br> 尽管如此，这仍是以快速医疗形式生效的，即失去吸血转化为快速医疗，因此获得的每点快速医疗会携带有12医疗点，你最多以此法转换传奇耐力*2点吸血。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
